31→export const generateMidGalaxyStars = (count = 800, seed = 137) => {
32→    const rng = mulberry32(seed);
33→    const stars = new Array(count);
34→    for (let i = 0; i < count; i++) {
35→        const color = STAR_COLORS[Math.floor(rng() * STAR_COLORS.length)];
36→        stars[i] = {
37→            x: rng() * WORLD_SPAN - HALF_SPAN,
38→            y: rng() * WORLD_SPAN - HALF_SPAN,
39→            radius: 1 + rng() * 3,
40→            opacity: 0.3 + rng() * 0.5,
41→            color,
42→        };
43→    }
44→    return stars;
45→};
