 21→/** Seeded RNG */
 22→const seededRng = (seed) => {
 23→    let s = seed | 0;
 24→    return () => {
 25→        s = (s + 0x6D2B79F5) | 0;
 26→        let t = Math.imul(s ^ (s >>> 15), 1 | s);
 27→        t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
 28→        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
 29→    };
 30→};
