101→                allDust.push({
102→                    gx: galaxy.x,
103→                    gy: galaxy.y,
104→                    localX, localY,
105→                    twinkleSpeed, twinklePhase,
106→                    driftSpeed, driftAngle, driftRadius,
107→                    baseAlpha, size,
108→                    r, g, b,
109→                });
