        radius: getStarRadius(likeCount),
        title: post.title || '',
        authorName: post.users?.name ?? post.user_name ?? 'Anonymous',
        likeCount,
        post,  // keep reference for navigation
    };
});

// Initial sort
rebuildSortedIndices();
activeRef.current = true;
startLoop();
```

**rAF loop** `tick()`:

```js
const tick = () => {
    if (!activeRef.current) return;

    const keys = keysRef.current;
    const dt = 1; // fixed timestep (frame-based)

    // 1. Heading update (A/D)
    if (keys.a) heading.current -= TURN_RATE;
    if (keys.d) heading.current += TURN_RATE;

    // 2. Velocity update (W/S)
    if (keys.w) velocity.current = Math.min(velocity.current + ACCEL, MAX_SPEED);
    else if (keys.s) velocity.current = Math.max(velocity.current - BRAKE, -MAX_SPEED * 0.3);
    else velocity.current *= FRICTION;

    // Clamp near-zero
    if (Math.abs(velocity.current) < 0.01) velocity.current = 0;

    // 3. Update rocket world position
    const h = heading.current;
    const v = velocity.current;
    rocketPos.current.x += Math.cos(h) * v;
    rocketPos.current.y += Math.sin(h) * v;

    // 4. Update star z values (simulate forward motion)
    const stars = starsRef.current;
    for (let i = 0; i < stars.length; i++) {
        stars[i].z -= v * 0.5; // z decreases as we move forward

        // Recycle stars that pass behind camera
        if (stars[i].z < MIN_Z) {
            stars[i].z = MAX_Z - Math.random() * SPAWN_Z_RANGE;
            // Scatter around current rocket position
            stars[i].worldX = rocketPos.current.x + (Math.random() - 0.5) * 2000;
            stars[i].worldY = rocketPos.current.y + (Math.random() - 0.5) * 2000;
        }
        // Also recycle if too far behind
        if (stars[i].z > MAX_Z + 100) {
            stars[i].z = MIN_Z + Math.random() * 20;
        }
    }

    // 5. Sort every SORT_INTERVAL frames
    frameRef.current++;
    if (frameRef.current % SORT_INTERVAL === 0) {
        rebuildSortedIndices();
    }

    // 6. Find targeted star
    updateTarget();

    // 7. Trigger canvas redraw
    if (layerRef.current) {
        layerRef.current.batchDraw();
    }

    rafRef.current = requestAnimationFrame(tick);
};
```

**Projection helper** (consumed by RocketLayer's sceneFunc):

```js
const project = (star, cx, cy) => {
    const relX = star.worldX - rocketPos.current.x;
    const relY = star.worldY - rocketPos.current.y;

    // Rotate by negative heading so "forward" is screen-up
    const cosH = Math.cos(-heading.current + Math.PI / 2);
    const sinH = Math.sin(-heading.current + Math.PI / 2);
    const rotX = relX * cosH - relY * sinH;
    const rotY = relX * sinH + relY * cosH;

    const projX = cx + rotX / star.z;
    const projY = cy + rotY / star.z;
    const scale = 1 / star.z;

    return { projX, projY, scale };
};
```

**Target update**:

```js
const updateTarget = () => {
    const cx = screenCenter.current.x;
    const cy = screenCenter.current.y;
    const stars = starsRef.current;
    let bestIdx = -1;
    let bestDist = TARGET_DIST_MAX;

    for (let i = 0; i < stars.length; i++) {
        if (stars[i].z < TARGET_Z_MIN || stars[i].z > MAX_Z * 0.8) continue;
        const { projX, projY } = project(stars[i], cx, cy);
        const dx = projX - cx;
        const dy = projY - cy;
        const d = Math.sqrt(dx * dx + dy * dy);
        if (d < bestDist) {
            bestDist = d;
            bestIdx = i;
        }
    }
    targetIndexRef.current = bestIdx;
};
```

**Key handlers** (registered/unregistered on enter/exit):

```js
const handleKeyDown = (e) => {
    const key = e.key.toLowerCase();
    if (key === 'w' || key === 'arrowup') keysRef.current.w = true;
    if (key === 's' || key === 'arrowdown') keysRef.current.s = true;
    if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
    if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
};

const handleKeyUp = (e) => {
    const key = e.key.toLowerCase();
    if (key === 'w' || key === 'arrowup') keysRef.current.w = false;
    if (key === 's' || key === 'arrowdown') keysRef.current.s = false;
    if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
    if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
};
